import{_ as l,a as i,b as o}from"./chunks/DriverUpdateSuccessfully.Cjcb7A7z.js";import{_ as r,o as t,c as a,a3 as c}from"./chunks/framework.DXXx-gl1.js";const b=JSON.parse('{"title":"下载与安装驱动","description":"","frontmatter":{},"headers":[],"relativePath":"zh/InstallationGuides/InstallDrivers.md","filePath":"zh/InstallationGuides/InstallDrivers.md","lastUpdated":1731211468000}'),d={name:"zh/InstallationGuides/InstallDrivers.md"};function s(n,e,p,u,h,m){return t(),a("div",null,[...e[0]||(e[0]=[c('<h1 id="下载与安装驱动" tabindex="-1">下载与安装驱动 <a class="header-anchor" href="#下载与安装驱动" aria-label="Permalink to &quot;下载与安装驱动&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>出于安全启动和稳定发布需要，部分设备的驱动包在开发者的仓库中单独发布（例如小米平板5、小米9等）， 本文介绍的是从GIT仓库下载安装驱动的方法。</p></div><h2 id="准备" tabindex="-1">准备 <a class="header-anchor" href="#准备" aria-label="Permalink to &quot;准备&quot;">​</a></h2><ul><li><p>下载<a href="https://github.com/WOA-Project/DriverUpdater/releases" target="_blank" rel="noreferrer">DriverUpdater</a>.</p><blockquote><p>通常来说，请下载x64/x86的版本.</p></blockquote></li><li><p>下载平台通用驱动包</p><blockquote><p>点击页面上的<code>Download</code>按钮下载即可. <img src="'+l+'" width="40%/"></p></blockquote><ul><li>对于搭载SD855的设备, 驱动库位于 <a href="https://github.com/Project-Aloha/msmnile-Drivers" target="_blank" rel="noreferrer">msmnile-Drivers</a></li><li>对于搭载SD720的设备, 驱动库位于 <a href="https://github.com/Project-Aloha/Atoll-Drivers" target="_blank" rel="noreferrer">Atoll-Drivers</a></li><li>其他平台以此类推.</li></ul></li><li><p>下载适用于单独设备的驱动包</p><blockquote><p>点击<code>Download</code>按钮下载即可. <img src="'+i+'" width="40%/"></p></blockquote><ul><li>对于小米平板五, 仓库在 <a href="https://github.com/Project-Aloha/Raphael" target="_blank" rel="noreferrer">Nabu</a>.</li><li>对于一加7T Pro, 仓库在 <a href="https://github.com/Project-Aloha/Hotdog" target="_blank" rel="noreferrer">Hotdog</a>.</li><li>对于其他设备, 可以参考<a href="/DocumentWebsite/ReferenceTables/DeviceCodenameReferenceTable.html">设备代号参考表</a>类推.</li></ul></li><li><p>手机进入大容量模式 <a href="./EnterUMS.html">大容量模式</a>.</p><blockquote><p>通常来说，刚刚释放完Windows，你的手机应该仍处于大容量模式下.</p></blockquote></li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><ol><li><p>解压刚刚下载的压缩包包，并确保路径正确.</p><ul><li>样例: <ul><li>将平台通用驱动解压在 <code>D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\</code></li><li>将DriverUpdater解压至 <code>D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\DriverUpdater.exe</code></li><li>将设备特殊驱动解压至 <code>D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\components\\QC8150\\Device\\&lt;device-codename&gt;\\</code></li></ul></li></ul></li><li><p>打开一个管理员终端, 切换目录至 <code>&lt;silicon-codename&gt;-Drivers\\</code>.</p><ul><li><code>cmd</code>命令: <ul><li><code>cd /d D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\</code></li></ul></li><li><code>powershell</code>命令: <ul><li><code>cd &#39;D:\\WOA\\&lt;silicon-codename&gt;-Drivers\\&#39;</code></li></ul></li></ul></li><li><p>使用<code>DriverUpdater.exe</code>安装驱动</p><ul><li>对于详细的参数介绍，请执行 <code>DriverUpdater.exe --help</code>.</li><li>样例： (假设大容量情况下手机的Windows分区在电脑上显示为<code>F盘</code>): <ul><li><code>.\\DriverUpdater.exe -p F: -d definitions\\Desktop\\ARM64\\Internal\\&lt;device-codename&gt;.txt -r .</code></li><li><code>.\\DriverUpdater.exe -p F: -d definitions\\Desktop\\ARM64\\Internal\\&lt;device-codename&gt;.xml -r .</code></li></ul></li></ul></li><li><p>等待完成</p><ul><li>例如QRD778释放成功的图片: <img src="'+o+'"></li></ul></li><li><p>在电脑上弹出磁盘, 大功告成。</p></li></ol>',6)])])}const v=r(d,[["render",s]]);export{b as __pageData,v as default};
